export default function Contact() {
  const [form, setForm] = useState({ name: "", email: "", message: "" });
  const [sending, setSending] = useState(false);
  const [sent, setSent] = useState(false);
  const [error, setError] = useState(false);
  const [focused, setFocused] = useState(null);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const btnRef = useRef(null);
  const formRef = useRef(null);

  useEffect(() => {
    const isTouchDevice =
      window.matchMedia("(pointer: coarse)").matches ||
      window.matchMedia("(max-width: 768px)").matches ||
      "ontouchstart" in window;

    if (isTouchDevice) {
      setMousePos({ x: 0, y: 0 });
      return;
    }

    const handleMove = (e) => {
      if (!btnRef.current) return;
      const r = btnRef.current.getBoundingClientRect();
      const x = e.clientX - (r.left + r.width / 2);
      const y = e.clientY - (r.top + r.height / 2);
      const dist = Math.sqrt(x * x + y * y);
      if (dist < 120) {
        setMousePos({ x: x * 0.35, y: y * 0.35 });
      } else {
        setMousePos({ x: 0, y: 0 });
      }
    };

    window.addEventListener("mousemove", handleMove);
    return () => window.removeEventListener("mousemove", handleMove);
  }, []);

  const handleChange = (key) => (e) => {
    const value =
      key === "message" ? e.target.value.slice(0, 500) : e.target.value;
    setForm((prev) => ({ ...prev, [key]: value }));
  };

  const handleSend = async (e) => {
    e.preventDefault();
    if (!form.name || !form.email || !form.message) return;

    setSending(true);
    setError(false);

    try {
      await emailjs.send(
        EMAILJS_SERVICE_ID,
        EMAILJS_TEMPLATE_ID,
        {
          from_name: form.name,
          from_email: form.email,
          message: form.message,
          to_email: "himeshchakrapani6@gmail.com",
        },
        EMAILJS_PUBLIC_KEY,
      );

      setSent(true);
      setForm({ name: "", email: "", message: "" });
    } catch {
      setError(true);
    } finally {
      setSending(false);
    }
  };

  return (
    <section className="contact-page">
      <div className="contact-orb orb-a" />
      <div className="contact-orb orb-b" />
      <div className="contact-orb orb-c" />

      <div className="contact-grid">
        <aside className="contact-info">
          <h2 className="contact-headline">
            <span className="reveal" style={{ animationDelay: "0.1s" }}>
              Let&apos;s create
            </span>
            <span className="reveal" style={{ animationDelay: "0.2s" }}>
              something
            </span>
            <span
              className="reveal headline-gradient"
              style={{ animationDelay: "0.3s" }}
            >
              great.
            </span>
          </h2>

          <p
            className="availability-badge reveal"
            style={{ animationDelay: "0.38s" }}
          >
            <span className="status-dot" />
            Available for new projects
          </p>

          <p
            className="contact-email reveal"
            style={{ animationDelay: "0.44s" }}
          >
            himeshchakrapani6@gmail.com
          </p>

          <div className="social-list">
            {SOCIALS.map((social, i) => (
              <a
                key={social.label}
                className="social-item reveal"
                style={{ animationDelay: `${0.5 + i * 0.12}s` }}
                href={social.href}
                target="_blank"
                rel="noreferrer"
              >
                <span
                  className="social-icon"
                  style={{
                    background: `${social.color}1f`,
                    borderColor: `${social.color}33`,
                  }}
                >
                  <SocialIcon type={social.icon} color={social.color} />
                </span>

                <span className="social-text">
                  <span className="social-label">{social.label}</span>
                  <span className="social-handle">{social.handle}</span>
                </span>

                <span className="social-arrow">↗</span>
              </a>
            ))}
          </div>
        </aside>

        <div
          className="contact-form-card reveal"
          style={{ animationDelay: "0.3s" }}
        >
          <span className="card-shimmer" />

          {sent ? (
            <div className="success-state">
              <div className="success-check">✓</div>
              <h3>Message sent!</h3>
              <p>I&apos;ll get back to you within 24 hours.</p>
              <button
                type="button"
                className="send-another-btn"
                onClick={() => setSent(false)}
              >
                Send another
              </button>
            </div>
          ) : (
            <form ref={formRef} className="contact-form" onSubmit={handleSend}>
              <div
                className={`field-group ${focused === "name" ? "is-focused" : ""}`}
              >
                <label htmlFor="contact-name">Name</label>
                <span className="field-accent" />
                <input
                  id="contact-name"
                  type="text"
                  value={form.name}
                  onChange={handleChange("name")}
                  onFocus={() => setFocused("name")}
                  onBlur={() => setFocused(null)}
                  placeholder="Your name"
                  autoComplete="name"
                />
              </div>

              <div
                className={`field-group ${focused === "email" ? "is-focused" : ""}`}
              >
                <label htmlFor="contact-email">Email</label>
                <span className="field-accent" />
                <input
                  id="contact-email"
                  type="email"
                  value={form.email}
                  onChange={handleChange("email")}
                  onFocus={() => setFocused("email")}
                  onBlur={() => setFocused(null)}
                  placeholder="you@example.com"
                  autoComplete="email"
                />
              </div>

              <div
                className={`field-group ${focused === "message" ? "is-focused" : ""}`}
              >
                <label htmlFor="contact-message">Message</label>
                <span className="field-accent" />
                <textarea
                  id="contact-message"
                  value={form.message}
                  onChange={handleChange("message")}
                  onFocus={() => setFocused("message")}
                  onBlur={() => setFocused(null)}
                  placeholder="Tell me about your project"
                  maxLength={500}
                />
                <div
                  className="char-counter"
                  style={{
                    color:
                      form.message.length > 450
                        ? "#f72585"
                        : "rgba(240,240,255,0.2)",
                  }}
                >
                  {form.message.length} / 500
                </div>
              </div>

              <button
                ref={btnRef}
                type="submit"
                className={`send-btn ${sent ? "is-sent" : ""}`}
                onClick={handleSend}
                disabled={sending}
                style={{
                  transform: `translate(${mousePos.x}px, ${mousePos.y}px)`,
                  transition:
                    mousePos.x === 0
                      ? "transform 0.5s cubic-bezier(0.16,1,0.3,1)"
                      : "transform 0.1s linear",
                }}
              >
                {sending ? (
                  <span className="btn-state">
                    <span className="btn-spinner" />
                    Sending...
                  </span>
                ) : sent ? (
                  <span className="btn-state">✓ Message Sent!</span>
                ) : (
                  <span className="btn-state">Send Message →</span>
                )}
              </button>

              {error && (
                <p className="form-error">
                  Something went wrong. Try{" "}
                  <a
                    href="https://wa.me/918432419551?text=Hi%20Abhi%2C%20I%20saw%20your%20portfolio%20and%20would%20love%20to%20work%20together!"
                    target="_blank"
                    rel="noreferrer"
                  >
                    WhatsApp
                  </a>{" "}
                  instead.
                </p>
              )}
            </form>
          )}
        </div>
      </div>
    </section>
  );
}
